import numpy as np
try:
    from psychopy import core, visual
except ImportError:
    print("Psychopy not downloaded.")


class MainExpInterface:
    def __init__(self, fullscr=False):
        if fullscr:
            self.win = visual.Window(fullscr=True, color="black", units="norm")
            self.win_width, self.win_height = self.win.size
        else:
            self.win_width, self.win_height = 800, 600 # Mid-screen = 0,0, x_left = -400
            self.win = visual.Window(size=[self.win_width, self.win_height], fullscr=False, color="black", units="norm")

        self.fixation_cross = visual.TextStim(text="+", win=self.win, color="white", height=0.2)

    def fix_cross(self, duration=10.0):
        self.fixation_cross.draw()
        self.notifications_box.draw()
        self.win.flip()
        core.wait(duration)
    
    def build_chart(self, values):
        margin_left = -1 + 2*0.1
        margin_right = -1 + 2*0.75
        margin_bottom = -1 + 2*0.1
        margin_up = -1 + 2*0.9

        bottom_y, top_y = (values[0]*0.85, values[0]*1.15)

        ys = np.interp(values, (bottom_y, top_y), (margin_bottom, margin_up))
        y_mid_px = np.interp(values[0], (bottom_y, top_y), (margin_bottom, margin_up))

        xs = np.linspace(margin_left, margin_right, len(values))
        ys = np.interp(values, (bottom_y, top_y), (margin_bottom, margin_up))
        vertices = list(zip(xs, ys))

        x_axis = visual.Line(self.win, start=(margin_left, margin_bottom), end=(margin_right, margin_bottom),
                     lineColor='white', lineWidth=2)
        
        y_axis = visual.Line(self.win, start=(margin_left, margin_bottom), end=(margin_left, margin_up),
                     lineColor='white', lineWidth=2)

        line = visual.ShapeStim(self.win, vertices=vertices[:2], closeShape=False,
                        lineColor='green', fillColor=None, lineWidth=3)


        midline = visual.Line(self.win, 
                      start=(margin_left, y_mid_px), 
                      end=(margin_right, y_mid_px),
                      lineColor='grey', 
                      lineWidth=1)

        for i in range(2, len(values) + 1):
            line.vertices = vertices[:i]
            x_axis.draw()
            y_axis.draw()
            line.draw()
            midline.draw()
            self.win.flip()
            core.wait(0.1)

        core.wait(20.0)


